import type { DMMF } from '@prisma/dmmf'

/**
 * Maps a Prisma DMMF field to its TypeScript type representation.
 * Object (relation) fields resolve to the related model name; enum fields
 * resolve to the enum type alias; scalar fields use the built-in type map.
 */
function prismaTypeToTs(field: DMMF.Field): string {
  if (field.kind === 'object') {
    const base = field.type
    return field.isList ? `${base}[]` : `${base} | null`
  }

  if (field.kind === 'enum') {
    return field.type
  }

  const scalarMap: Record<string, string> = {
    String: 'string',
    Boolean: 'boolean',
    Int: 'number',
    Float: 'number',
    Decimal: 'number',
    BigInt: 'bigint',
    DateTime: 'Date',
    Bytes: 'Uint8Array',
    Json: 'unknown',
  }
  return scalarMap[field.type] ?? 'unknown'
}

/**
 * Converts a model name to a lowercase, pluralised URL segment for REST paths.
 * E.g. "UserProfile" → "user-profiles".
 */
function toUrlSegment(modelName: string): string {
  // Insert hyphens before uppercase letters that follow a lowercase letter or
  // another uppercase letter followed by a lowercase letter, then lowercase.
  const kebab = modelName
    .replace(/([a-z])([A-Z])/g, '$1-$2')
    .replace(/([A-Z]+)([A-Z][a-z])/g, '$1-$2')
    .toLowerCase()

  // Naively pluralise by appending "s" (or "es" for words ending in s/x/z/ch/sh).
  if (/(?:s|x|z|ch|sh)$/.test(kebab)) {
    return `${kebab}es`
  }
  if (kebab.endsWith('y') && !/[aeiou]y$/.test(kebab)) {
    return `${kebab.slice(0, -1)}ies`
  }
  return `${kebab}s`
}

/**
 * Returns the ID field of a model (the field with `isId: true`), or `undefined`
 * when no single-field ID is defined.
 */
function idField(model: DMMF.Model): DMMF.Field | undefined {
  return model.fields.find((f) => f.isId)
}

/**
 * Generates a TypeScript string-union type alias for a Prisma enum.
 *
 * Example output:
 * ```ts
 * export type Role = 'ADMIN' | 'USER'
 * ```
 */
export function renderEnum(e: DMMF.DatamodelEnum): string {
  const values = e.values.map((v) => `'${v.name}'`).join(' | ')
  return `export type ${e.name} = ${values}`
}

/**
 * Generates a TypeScript interface for a Prisma model, covering all fields
 * (scalars, enums, and relations). Optional fields are marked with `?`.
 *
 * Example output:
 * ```ts
 * export interface User {
 *   id: number
 *   email: string
 *   name?: string
 * }
 * ```
 */
export function renderModelInterface(model: DMMF.Model): string {
  const fields = model.fields
    .map((f) => {
      const tsType = prismaTypeToTs(f)
      const optional = !f.isRequired ? '?' : ''
